int
write_portEnable(int      action,
            u_char   *var_val,
            u_char   var_val_type,
            size_t   var_val_len,
            u_char   *statP,
            oid      *name,
            size_t   name_len)
{
    long value;
    int size;
    ulong index;

    index = UP2LP(name[name_len-1]);

    switch ( action ) {
        case RESERVE1:
          if (var_val_type != ASN_INTEGER) {
              fprintf(stderr, "write to PoeMib not ASN_INTEGER\n");
              return SNMP_ERR_WRONGTYPE;
          }
          if (var_val_len > sizeof(long)) {
              fprintf(stderr,"write to PoeMib: bad length\n");
              return SNMP_ERR_WRONGLENGTH;
          }

          if(IS_LOGIC_PORT_INVALID(index))
            return SNMP_ERR_NOTWRITABLE;

          break;

        case RESERVE2:
          	size  = var_val_len;
          	value = * (long *) var_val;
			if(value == 1)
			{
				value = 1;/* XXX */
			}
			else if(value == 2)
			{
				value = 0;/* XXX */
			}
			else 
			{
				return SNMP_ERR_NOERROR;
			}
          	SYS_ERR_CHK(sal_poe_portEnable_set(index, value));
          break;

        case FREE:
             /* Release any resources that have been allocated */
          break;

        case ACTION:
             /*
              * The variable has been stored in 'value' for you to use,
              * and you have just been asked to do something with it.
              * Note that anything done here must be reversable in the UNDO case
              */
          break;

        case UNDO:
             /* Back out any changes made in the ACTION case */
          break;

        case COMMIT:
             /*
              * Things are working well, so it's now safe to make the change
              * permanently.  Make sure that anything done here can't fail!
              */
          break;
    }
    return SNMP_ERR_NOERROR;
}
